// ---- compatibility guard: fail loudly, not silently ----
function __fatal(msg){
  try{
    var t=document.getElementById('loadTag');
    var hb=document.getElementById('loadHeadline');
    if(hb) hb.textContent='CAN\'T RUN HERE';
    if(t) t.innerHTML=msg;
    var pc=document.getElementById('loadPct'); if(pc) pc.textContent='!';
    var bar=document.getElementById('loadBar'); if(bar){bar.style.width='100%';bar.style.background='#8a2323';}
    var eb=document.getElementById('enterBtn'); if(eb) eb.style.display='none';
  }catch(e){}
}
window.addEventListener('error',function(){
  __fatal('THIS APP OR PREVIEW CAN\'T RUN THE 3D GAME.<br>OPEN THE DOWNLOADED FILE IN CHROME OR SAFARI.<br>ON A PHONE, PLAY THE HOSTED LINK INSTEAD.');
});
(function(){
  var ok=false;
  try{ var c=document.createElement('canvas');
    ok=!!(window.WebGLRenderingContext&&(c.getContext('webgl')||c.getContext('experimental-webgl')));
  }catch(e){ ok=false; }
  if(!ok) throw new Error('WebGL unavailable in this viewer');
})();

