function buildRuntimeProducts(content){
  const drops=(content&&Array.isArray(content.drops))?content.drops:[];
  return BASE_PRODUCTS.map((base,i)=>{
    const drop=drops[i]||{};
    return {
      ...base,
      name: drop.name || base.name,
      price: typeof drop.priceCoins==='number' ? drop.priceCoins : base.price,
      demand: drop.demand || base.demand,
      color: drop.color ? `${drop.color} // ${base.color.split('//')[1]?.trim()||'Limited Drop'}` : base.color,
      cmsDropId: drop.id || null,
      sku: drop.sku || null,
      active: typeof drop.active==='boolean' ? drop.active : true,
    };
  });
}

function missionRewardLabel(id,rewardCoins,baseReward){
  if(typeof rewardCoins!=='number') return baseReward;
  if(id==='stash') return `LEVEL DEAL + ${rewardCoins} coins`;
  if(rewardCoins<=0) return baseReward;
  return `+${rewardCoins} coins`;
}

function buildRuntimeLevels(content){
  const chapters=(content&&Array.isArray(content.chapters))?content.chapters:[];
  return BASE_LEVELS.map((base,idx)=>{
    const chapter=chapters[idx]||{};
    const chapterMissions=Array.isArray(chapter.missions)?chapter.missions:[];
    const missions=base.missions.map((baseMission,mIdx)=>{
      const mapped=chapterMissions.find(m=>m&&m.id===baseMission.id) || chapterMissions[mIdx] || {};
      const coins=typeof mapped.rewardCoins==='number' ? mapped.rewardCoins : baseMission.coins;
      return {
        ...baseMission,
        id: mapped.id || baseMission.id,
        title: mapped.title || baseMission.title,
        coins,
        reward: missionRewardLabel(baseMission.id, mapped.rewardCoins, baseMission.reward),
      };
    });

    return {
      ...base,
      num: chapter.number || base.num,
      name: chapter.name || base.name,
      sub: chapter.subtitle || base.sub,
      code: chapter.stash?.code || base.code,
      deal: chapter.stash?.deal || base.deal,
      roomVisualKey: chapter.roomVisualKey || null,
      unlockWindow: chapter.unlockWindow || null,
      isActive: typeof chapter.isActive==='boolean' ? chapter.isActive : true,
      moralFocus: chapter.moralFocus || null,
      dropId: chapter.dropId || null,
      missions,
    };
  });
}

