function restoreMissionProgress(progressByLevel){
  if(!Array.isArray(progressByLevel)) return;
  progressByLevel.forEach((missionIds,levelIdx)=>{
    if(!Array.isArray(missionIds)||!LEVELS[levelIdx]) return;
    LEVELS[levelIdx].missions.forEach(m=>{ m.done=missionIds.includes(m.id); });
  });
}

function missionProgressSnapshot(){
  return LEVELS.map(level=>level.missions.filter(m=>m.done).map(m=>m.id));
}

// ---------------- GAME STATE ----------------
const state={ coins:1600, owned:[], level:0, walked:0, inspected:false,
  viewed:new Set(), codes:[], levelsCleared:0 };

const playerId=getOrCreatePlayerId();
let progressHydrated=false;
let persistTimer=null;

function queuePlayerEvent(type,payload={}){
  trackPlayerEvent(playerId,type,payload).catch(()=>{});
}

async function hydrateProgress(){
  if(progressHydrated) return;
  progressHydrated=true;
  try{
    const profile=await loadPlayerProfile(playerId);
    if(typeof profile.wallet?.coins==='number') state.coins=profile.wallet.coins;
    if(Array.isArray(profile.inventory?.ownedDropIds)) state.owned=profile.inventory.ownedDropIds.slice(0,PRODUCTS.length);
    if(typeof profile.progress?.currentLevel==='number') state.level=Math.max(0,Math.min(LEVELS.length-1,profile.progress.currentLevel));
    if(typeof profile.progress?.walked==='number') state.walked=profile.progress.walked;
    state.inspected=!!profile.progress?.inspected;
    if(Array.isArray(profile.progress?.viewed)) state.viewed=new Set(profile.progress.viewed);
    if(Array.isArray(profile.entitlements?.codes)) state.codes=profile.entitlements.codes;
    if(typeof profile.progress?.levelsCleared==='number') state.levelsCleared=profile.progress.levelsCleared;
    restoreMissionProgress(profile.progress?.missionProgress);
  }catch(_e){}
}

function persistProgress(){
  const profile=createDefaultPlayerProfile(playerId);
  profile.wallet.coins=state.coins;
  profile.inventory.ownedDropIds=[...state.owned];
  profile.progress.currentLevel=state.level;
  profile.progress.levelsCleared=state.levelsCleared;
  profile.progress.walked=state.walked;
  profile.progress.inspected=state.inspected;
  profile.progress.viewed=Array.from(state.viewed);
  profile.progress.missionProgress=missionProgressSnapshot();
  profile.entitlements.codes=[...state.codes];

  if(persistTimer) clearTimeout(persistTimer);
  persistTimer=setTimeout(()=>{ savePlayerProfile(profile).catch(()=>{}); },220);
}

// ---------------- HELPERS / HUD ----------------
const $=s=>document.querySelector(s);
const fmt=n=>n.toLocaleString('en-GB');
const EXPOSURE_BASE_GAIN=1.3;
let userBrightnessScale=1.3;

function clamp(n,min,max){ return Math.max(min,Math.min(max,n)); }

function applyExposureForCurrentLevel(){
  const profile=ROOM_LIGHT_PROFILES[state.level]||ROOM_LIGHT_PROFILES[0];
  renderer.toneMappingExposure=profile.exposure*userBrightnessScale*EXPOSURE_BASE_GAIN;
}

function applyVisualSettings(){
  userBrightnessScale=clamp(Number(visualSettings.brightness)||1.3,.8,2.6);
  setRendererQuality();
  if(levelGroup) levelGroup.traverse(applyLightQuality);
  applyExposureForCurrentLevel();
  const q=qualityProfile();
  if(bloomPass){
    bloomPass.enabled=!!q.bloom;
    bloomPass.strength=q.bloomStrength+(visualSettings.bloom||0)*.6;
    bloomPass.radius=q.bloomRadius;
    bloomPass.threshold=q.bloomThreshold;
  }
}

function initDisplaySettings(){
  const root=$('#displaySettings');
  const cog=$('#displayCog');
  const panel=$('#displayPanel');
  const slider=$('#brightnessSlider');
  const value=$('#brightnessValue');
  const quality=$('#qualitySelect');
  const bloom=$('#bloomSlider');
  const bloomValue=$('#bloomValue');
  const resetBtn=$('#displayResetBtn');
  if(!root||!cog||!panel||!slider||!value||!quality||!bloom||!bloomValue||!resetBtn) return;

  const syncUI=()=>{
    const pct=Math.round((visualSettings.brightness||1.3)*100);
    slider.value=String(pct);
    value.textContent=pct+'%';
    quality.value=visualSettings.quality;
    const glowPct=Math.round((visualSettings.bloom||0)*100);
    bloom.value=String(glowPct);
    bloomValue.textContent=glowPct+'%';
  };

  loadVisualSettings();
  userBrightnessScale=clamp(Number(visualSettings.brightness)||1.3,.8,2.6);
  visualSettings.brightness=userBrightnessScale;
  visualSettings.quality=QUALITY_PROFILES[visualSettings.quality]?visualSettings.quality:deviceProfile.tier;
  visualSettings.bloom=clamp(Number(visualSettings.bloom)||0,.0,.6);
  syncUI();
  applyVisualSettings();

  cog.addEventListener('click',e=>{
    e.stopPropagation();
    root.classList.toggle('open');
  });

  panel.addEventListener('click',e=>e.stopPropagation());

  slider.addEventListener('input',()=>{
    visualSettings.brightness=clamp(Number(slider.value)/100,.8,2.6);
    syncUI();
    applyVisualSettings();
    saveVisualSettings();
  });

  quality.addEventListener('change',()=>{
    visualSettings.quality=quality.value;
    syncUI();
    applyVisualSettings();
    saveVisualSettings();
  });

  bloom.addEventListener('input',()=>{
    visualSettings.bloom=clamp(Number(bloom.value)/100,.0,.6);
    syncUI();
    applyVisualSettings();
    saveVisualSettings();
  });

  resetBtn.addEventListener('click',()=>{
    visualSettings={
      quality:deviceProfile.tier,
      brightness:1.3,
      bloom:0.25,
    };
    syncUI();
    applyVisualSettings();
    saveVisualSettings();
  });

  document.addEventListener('click',()=>root.classList.remove('open'));
}

function toast(html,ms=3000){ const t=$('#toast'); t.innerHTML=html; t.classList.add('on');
  clearTimeout(t._h); t._h=setTimeout(()=>t.classList.remove('on'),ms); }
function setCoins(n){ state.coins=n; $('#coinAmt').textContent=fmt(n); persistProgress(); }
function LV(){ return LEVELS[state.level]; }
function missionsDone(){ return LV().missions.every(m=>m.done); }
function progress(){
  const lv=LV(), done=lv.missions.filter(m=>m.done).length;
  const overall=Math.round(((state.levelsCleared)+(done/lv.missions.length))/LEVELS.length*100);
  $('#plPct').textContent=Math.min(100,overall)+'%';
  $('#plFill').style.width=Math.min(100,overall)+'%';
  const next=lv.missions.find(m=>!m.done);
  $('#objText').textContent = next ? next.title.toUpperCase() :
    (state.level<LEVELS.length-1 ? 'DOOR UNLOCKED — LEVEL UP' : 'YOU MADE IT');
  const found=lv.missions.find(m=>m.id==='stash')?.done;
  $('#stashLine').innerHTML='STASH: '+(found?'<span class="fnd">FOUND ✓</span>':'<span class="hid">STILL HIDDEN</span>');
}
function clearMission(id){
  const m=LV().missions.find(m=>m.id===id);
  if(!m||m.done) return;
  m.done=true;
  queuePlayerEvent('mission_cleared',{ level: LV().num, missionId: id, missionTitle: m.title });
  if(m.coins) setCoins(state.coins+m.coins);
  toast(`MISSION CLEARED — <span class="gold">${m.title.toUpperCase()}</span>${m.coins?` &nbsp;+${m.coins} COINS`:''}`);
  renderMissions(); progress();
  if(missionsDone()){
    if(state.level<LEVELS.length-1){
      doorLocked=false;
      if(doorGlowRef) doorGlowRef.material.emissiveIntensity=1.2;
      setTimeout(()=>toast(`<span class="gold">LEVEL CLEARED</span> — THE DOOR TO ${LEVELS[state.level+1].name} IS OPEN`,4200),1400);
    } else {
      setTimeout(()=>toast('<span class="gold">CHAPTER 1 COMPLETE</span> — THE WAREHOUSE IS YOURS',5000),1400);
    }
  }
  persistProgress();
}
function renderMissions(){
  const lv=LV();
  $('#missionList').innerHTML=lv.missions.map((m,i)=>`
    <div class="mission type ${m.done?'done':''}" style="--tilt:${(i%2?-1.2:1.4)+(i*.3-.6)}deg">
      <div class="m-num">LEVEL ${lv.num} · CASE 0${i+1}</div>
      <div class="m-title">${m.title.toUpperCase()}</div>
      <div class="m-desc">${m.desc}${m.id==='stash'?` <br><br><b>HINT:</b> ${lv.stashHint}`:''}</div>
      <div class="m-reward">REWARD: ${m.reward}</div>
    </div>`).join('');
  $('#codesFoot').innerHTML = state.codes.length ?
    '<br>CODES FOUND: '+state.codes.map(c=>`<b style="color:#8a2323">${c}</b>`).join(' · ') : '';
}
function afterPurchase(){
  const n=state.owned.length;
  if(n>=1) clearMission('own1');
  if(n>=2) clearMission('own2');
  if(n>=3) clearMission('own3');
  persistProgress();
}
function checkViewed(){ if(state.viewed.size>=4) clearMission('viewall'); }

