let levelGroup=null, interactables=[], ROOM={w:11,d:9,h:3.4};
let doorLocked=true, doorGlowRef=null, heroSpinRef=null, tvTexRef=null, dustRef=null, bulbRef=null;
let activeRoomAssetRequest=0;
function applyLightQuality(node){
  if(!(node?.isPointLight||node?.isSpotLight||node?.isDirectionalLight)) return;
  const q=qualityProfile();
  if(node.castShadow&&node.shadow?.mapSize){
    node.shadow.mapSize.set(q.shadowMapSize,q.shadowMapSize);
    node.shadow.needsUpdate=true;
  }
}
function G(o){
  if(o?.traverse){
    o.traverse(node=>{ applyLegacyLightCompatibility(node); applyLightQuality(node); });
  }else{
    applyLegacyLightCompatibility(o);
    applyLightQuality(o);
  }
  levelGroup.add(o);
  return o;
}
function tagInteract(o,name,action){ o.userData={name,action}; interactables.push(o); }
function shadows(o){ o.traverse(m=>{ if(m.isMesh){m.castShadow=m.receiveShadow=true;} }); return o; }

function shell(w,d,h,floorMat,wallMat,ceilCol){
  ROOM={w,d,h};
  const f=new THREE.Mesh(new THREE.PlaneGeometry(w,d),floorMat);
  f.rotation.x=-Math.PI/2; f.receiveShadow=true; G(f);
  const c=new THREE.Mesh(new THREE.PlaneGeometry(w,d),
    new THREE.MeshStandardMaterial({color:ceilCol,roughness:1}));
  c.rotation.x=Math.PI/2; c.position.y=h; G(c);
  const mk=(ww,x,y,z,ry,mat)=>{const m=new THREE.Mesh(new THREE.PlaneGeometry(ww,h),mat);
    m.position.set(x,y,z); m.rotation.y=ry; m.receiveShadow=true; G(m); return m;};
  return {
    back: mk(w,0,h/2,-d/2,0,wallMat),
    front:mk(w,0,h/2, d/2,Math.PI,wallMat),
    left: mk(d,-w/2,h/2,0, Math.PI/2,wallMat),
    right:mk(d, w/2,h/2,0,-Math.PI/2,wallMat),
  };
}
function bulb(x,y,z,intensity=1.4){
  const l=new THREE.PointLight(0xffc98a,intensity,12,1.8);
  l.position.set(x,y,z); l.castShadow=true; G(l);
  const b=new THREE.Mesh(new THREE.SphereGeometry(.06,12,12),
    new THREE.MeshBasicMaterial({color:0xffd9a0}));
  b.position.set(x,y,z); G(b);
  const wr=new THREE.Mesh(new THREE.CylinderGeometry(.008,.008,ROOM.h-y,6),
    new THREE.MeshBasicMaterial({color:0x090909}));
  wr.position.set(x,(y+ROOM.h)/2,z); G(wr);
  bulbRef={light:l,mesh:b,base:l.intensity};
  return l;
}
function dustMotes(color=0xc9b58a,op=.5){
  const geo=new THREE.BufferGeometry();
  const pos=new Float32Array(380*3);
  for(let i=0;i<380;i++){ pos[i*3]=(Math.random()-.5)*ROOM.w; pos[i*3+1]=Math.random()*ROOM.h; pos[i*3+2]=(Math.random()-.5)*ROOM.d; }
  geo.setAttribute('position',new THREE.BufferAttribute(pos,3));
  dustRef=new THREE.Points(geo,new THREE.PointsMaterial({color,size:.014,transparent:true,opacity:op}));
  G(dustRef);
}
function cashScatter(n=20){
  for(let i=0;i<n;i++){
    const bill=new THREE.Mesh(new THREE.PlaneGeometry(.16,.07),M.cash);
    bill.rotation.x=-Math.PI/2; bill.rotation.z=Math.random()*7;
    bill.position.set((Math.random()-.5)*(ROOM.w-2),.006+Math.random()*.01,(Math.random()-.5)*(ROOM.d-2));
    G(bill);}
}
function crates(list){ list.forEach(([x,z,r,sz])=>{
  const c=new THREE.Mesh(new THREE.BoxGeometry(sz,sz,sz),M.crate);
  c.position.set(x,sz/2,z); c.rotation.y=r; shadows(c); G(c);});
}
function sofa(x,z,ry,mat=M.sofaDark){
  const g=new THREE.Group();
  const seat=new THREE.Mesh(new THREE.BoxGeometry(2.2,.45,.9),mat); seat.position.y=.45;
  const back=new THREE.Mesh(new THREE.BoxGeometry(2.2,.7,.25),mat); back.position.set(0,.9,-.33);
  const aL=new THREE.Mesh(new THREE.BoxGeometry(.25,.75,.9),mat); aL.position.set(-1.1,.6,0);
  const aR=aL.clone(); aR.position.x=1.1;
  g.add(seat,back,aL,aR); g.position.set(x,0,z); g.rotation.y=ry; shadows(g); G(g); return g;
}
function evidenceBoard(x,y,z,ry){
  const b=new THREE.Mesh(new THREE.PlaneGeometry(2.6,1.62),
    new THREE.MeshStandardMaterial({map:boardTex,roughness:.9}));
  b.position.set(x,y,z); b.rotation.y=ry; G(b);
  tagInteract(b,'THE DRAWING BOARD',()=>{ openPanel('boardPanel'); clearMission('board'); });
  const lamp=new THREE.PointLight(0xd8b98a,1.1,4,1.8);
  lamp.position.set(x+Math.sin(ry)*.7, y+.6, z+Math.cos(ry)*.7);
  G(lamp);
  return b;
}
// garment photo cards
const texLoader=new THREE.TextureLoader(); const texCache={};
function garmentTex(design,side){ const k=design+side;
  if(!texCache[k]){ const t=texLoader.load(GARMENT_ASSETS[design][side]); t.anisotropy=8; texCache[k]=t; }
  return texCache[k]; }
function curvedPlane(w,h){
  const geo=new THREE.PlaneGeometry(w,h,12,1);
  const pos=geo.attributes.position;
  for(let i=0;i<pos.count;i++){ const x=pos.getX(i); pos.setZ(i,Math.cos((x/w)*Math.PI)*w*.06); }
  geo.computeVertexNormals(); return geo;
}
function buildGarment(product,height=1.5,lit=true){
  const g=new THREE.Group(); const w=height*product.ar;
  const Mat=lit?THREE.MeshStandardMaterial:THREE.MeshBasicMaterial;
  const mf=new Mat({map:garmentTex(product.design,'front')});
  const mb=new Mat({map:garmentTex(product.design,'back')});
  if(lit){ mf.roughness=mb.roughness=.92; }
  const fr=new THREE.Mesh(curvedPlane(w,height),mf);
  const bk=new THREE.Mesh(curvedPlane(w,height),mb);
  bk.rotation.y=Math.PI; bk.position.z=-.015; fr.position.z=.015;
  g.add(fr,bk); return g;
}
function heroDisplay(x,z,pi=0,h=1.7){
  const ped=new THREE.Mesh(new THREE.CylinderGeometry(.55,.65,.18,24),
    new THREE.MeshStandardMaterial({color:0x241d14,roughness:.5,metalness:.3}));
  ped.position.set(x,.09,z); ped.receiveShadow=true; G(ped);
  heroSpinRef=buildGarment(PRODUCTS[pi],h,true);
  heroSpinRef.position.set(x,.18+h/2,z); G(heroSpinRef);
  const hit=new THREE.Mesh(new THREE.CylinderGeometry(.65,.65,h+.3,10),
    new THREE.MeshBasicMaterial({visible:false}));
  hit.position.set(x,.2+h/2,z); G(hit);
  tagInteract(hit,PRODUCTS[pi].name.toUpperCase()+' — INSPECT',()=>openShop(pi));
  const sp=new THREE.SpotLight(0xf2e2c2,1.6,12,.6,.5,1.3);
  sp.position.set(x+.6,ROOM.h-.2,z+.9); sp.castShadow=true; G(sp);
  sp.target=heroSpinRef; G(sp.target);
}
function clothingRack(x,z,ry,indices,scale=1.15){
  const g=new THREE.Group();
  const W=Math.max(2.4,indices.length*1.0+.6);
  const bar=new THREE.Mesh(new THREE.CylinderGeometry(.02,.02,W,10),M.steel);
  bar.rotation.z=Math.PI/2; bar.position.y=2.05; g.add(bar);
  [-W/2+.1,W/2-.1].forEach(lx=>{
    const leg=new THREE.Mesh(new THREE.CylinderGeometry(.02,.02,2.05,8),M.steel);
    leg.position.set(lx,1.02,0); g.add(leg);
    const foot=new THREE.Mesh(new THREE.BoxGeometry(.06,.03,.7),M.steel);
    foot.position.set(lx,.015,0); g.add(foot);});
  indices.forEach((pi,i)=>{
    const lx=-W/2+.55+i*(W-1.1)/Math.max(1,indices.length-1);
    const hook=new THREE.Mesh(new THREE.TorusGeometry(.05,.008,8,16,Math.PI),M.steel);
    hook.position.set(lx,2.05,0); g.add(hook);
    const card=buildGarment(PRODUCTS[pi],scale,true);
    card.position.set(lx,1.38,0); g.add(card);
    const hit=new THREE.Mesh(new THREE.BoxGeometry(.85,1.3,.4),new THREE.MeshBasicMaterial({visible:false}));
    hit.position.set(lx,1.35,0); g.add(hit);
    tagInteract(hit,PRODUCTS[pi].name.toUpperCase()+' — INSPECT',()=>openShop(pi));
  });
  shadows(g); g.position.set(x,0,z); g.rotation.y=ry; G(g); return g;
}
// the hidden STASH package
function stash(x,y,z,ry=0){
  const g=new THREE.Group();
  const box=new THREE.Mesh(new THREE.BoxGeometry(.3,.18,.2),M.black);
  const band=new THREE.Mesh(new THREE.BoxGeometry(.31,.19,.06),M.gold);
  const band2=new THREE.Mesh(new THREE.BoxGeometry(.06,.19,.21),M.gold);
  g.add(box,band,band2);
  g.position.set(x,y,z); g.rotation.y=ry; shadows(g); G(g);
  const hit=new THREE.Mesh(new THREE.BoxGeometry(.5,.4,.45),new THREE.MeshBasicMaterial({visible:false}));
  hit.position.set(x,y,z); G(hit);
  tagInteract(hit,'???',()=>{
    if(LV().missions.find(m=>m.id==='stash')?.done) return;
    setCoins(state.coins+500);
    state.codes.push(LV().code);
    $('#stashText').textContent=`Tucked away exactly where the board said it'd be. Inside: 500 Trap Coins and a one-time deal for this level — ${LV().deal.toLowerCase()}.`;
    $('#stashCode').textContent='CODE: '+LV().code+' — '+LV().deal;
    openPanel('stashPanel');
    clearMission('stash');
  });
  return g;
}
// exit door to the next level
function levelDoor(x,z,ry,label){
  const g=new THREE.Group();
  const doorTex=canvasTex(256,512,(gg,w,h)=>{
    gg.fillStyle='#5a4632'; gg.fillRect(0,0,w,h);
    for(let i=0;i<700;i++){ gg.fillStyle=`rgba(${40+Math.random()*30},${30+Math.random()*20},16,${Math.random()*.35})`;
      gg.fillRect(Math.random()*w,Math.random()*h,2,Math.random()*40);}
    gg.strokeStyle='rgba(30,22,12,.7)'; gg.lineWidth=8;
    gg.strokeRect(34,40,w-68,h*.34); gg.strokeRect(34,h*.46,w-68,h*.42);});
  const door=new THREE.Mesh(new THREE.BoxGeometry(1.15,2.25,.1),
    new THREE.MeshStandardMaterial({map:doorTex,roughness:.8}));
  door.position.y=1.12; g.add(door);
  const frame=new THREE.Mesh(new THREE.BoxGeometry(1.35,2.4,.06),M.woodDark);
  frame.position.set(0,1.2,.045); g.add(frame);
  const hnd=new THREE.Mesh(new THREE.SphereGeometry(.035,10,10),M.knob);
  hnd.position.set(-.38,1.1,-.07); g.add(hnd);
  const glow=new THREE.Mesh(new THREE.PlaneGeometry(1.62,2.62),
    new THREE.MeshStandardMaterial({color:0x000000,emissive:0xc9a06a,emissiveIntensity:.1,transparent:true,opacity:.9}));
  glow.position.set(0,1.2,-.052); g.add(glow);
  doorGlowRef=glow;
  shadows(g); g.position.set(x,0,z); g.rotation.y=ry; G(g);
  tagInteract(door,label,()=>{
    if(doorLocked){
      $('#doorIcon').textContent='🔒';
      $('#doorTitle').textContent=LEVELS[state.level+1]?LEVELS[state.level+1].name:'???';
      $('#doorText').textContent="It won't budge. Clear every case on the drawing board — including the stash — and the way up opens.";
      $('#doorReq').textContent='REQUIRES: ALL MISSIONS CLEARED';
      openPanel('doorPanel');
    } else nextLevel();
  });
  return g;
}

