// ==================== LEVEL LOADING ====================
let bounds={insetX:.5,insetZ:.5};
function applyRoomLightingProfile(levelIdx){
  const profile=ROOM_LIGHT_PROFILES[levelIdx]||ROOM_LIGHT_PROFILES[0];
  levelGroup.traverse(o=>{
    if(o?.isAmbientLight) o.intensity*=profile.ambient;
    if(o?.isHemisphereLight) o.intensity*=profile.hemi;
    if(o?.isDirectionalLight) o.intensity*=profile.directional;
    if(o?.isPointLight) o.intensity*=profile.point;
    if(o?.isSpotLight) o.intensity*=profile.spot;
  });
  renderer.toneMappingExposure=profile.exposure*userBrightnessScale*EXPOSURE_BASE_GAIN;
  if(bulbRef?.light) bulbRef.base=bulbRef.light.intensity;
  if(tvTexRef) tvTexRef._flickerScale=profile.point;
}
function applySceneConfigOverrides(sceneConfig){
  if(!sceneConfig) return;
  if(sceneConfig.fog) scene.fog=new THREE.FogExp2(sceneConfig.fog[0],sceneConfig.fog[1]);
  if(sceneConfig.background!==undefined) scene.background=new THREE.Color(sceneConfig.background);
  if(sceneConfig.bounds) bounds={insetX:sceneConfig.bounds.insetX,insetZ:sceneConfig.bounds.insetZ};
  if(sceneConfig.spawn) camera.position.set(sceneConfig.spawn[0],sceneConfig.spawn[1]??1.6,sceneConfig.spawn[2]);
  if(typeof sceneConfig.yaw==="number") yaw=sceneConfig.yaw;
  if(typeof sceneConfig.pitch==="number") pitch=sceneConfig.pitch;
}
function loadLevel(i, showIntro=true){
  state.level=i;
  const roomAssetRequest=++activeRoomAssetRequest;
  doorLocked=false; doorGlowRef=null; heroSpinRef=null; tvTexRef=null; dustRef=null; bulbRef=null;
  // tear down previous
  if(levelGroup){
    levelGroup.traverse(o=>{ if(o.geometry) o.geometry.dispose(); });
    scene.remove(levelGroup);
  }
  interactables=[]; hoverObj=null;
  levelGroup=new THREE.Group(); scene.add(levelGroup);
  const cfg=BUILDERS[i]();
  applyRoomLightingProfile(i);
  doorLocked=!missionsDone();               // stays open if somehow already cleared
  scene.environment=null;
  scene.fog=new THREE.FogExp2(cfg.fog[0],cfg.fog[1]);
  scene.background=new THREE.Color(cfg.bg);
  applyRoomAssetLayer({
    levelIndex:i,
    levelGroup,
    scene,
    assetPipeline,
    decorateNode:applyLightQuality,
    shouldApply:()=>roomAssetRequest===activeRoomAssetRequest&&levelGroup?.parent===scene,
  }).then(result=>{
    if(!result?.applied) return;
    if(roomAssetRequest!==activeRoomAssetRequest||levelGroup?.parent!==scene) return;
    applySceneConfigOverrides(result.sceneConfig);
  }).catch(err=>console.warn("Room asset layer failed",err));
  bounds={insetX:cfg.insetX,insetZ:cfg.insetZ};
  camera.position.set(cfg.spawn[0],1.6,cfg.spawn[1]);
  yaw=cfg.yaw; pitch=0;
  $('#levelLabel').textContent=`LEVEL ${LV().num} — ${LV().name}`;
  renderMissions(); progress();
  setTimeout(()=>{     // sync progress carried over from earlier levels
    if(state.walked>6) clearMission('walk');
    if(state.inspected) clearMission('inspect');
    afterPurchase(); checkViewed();
  },1200);
  if(showIntro){
    const li=$('#levelIntro');
    $('#liNum').textContent='LEVEL '+LV().num;
    $('#liName').textContent=LV().name;
    $('#liSub').textContent=LV().sub;
    li.classList.add('on');
    setTimeout(()=>li.classList.remove('on'),2600);
  }
}
function nextLevel(){
  const f=$('#fader'); f.classList.add('on');
  state.levelsCleared++;
  queuePlayerEvent('level_advanced',{ toLevelIndex: state.level+1 });
  persistProgress();
  setTimeout(()=>{
    loadLevel(state.level+1);
    setTimeout(()=>f.classList.remove('on'),250);
    if(state.level===LEVELS.length-1)
      setTimeout(()=>toast('THE FINAL FLOOR — <span class="gold">MAKE IT YOURS</span>',4000),1200);
  },750);
}

// ==================== CONTROLS ====================
const controls={enabled:false};
const keys={};
const pointerLockSupported=typeof renderer.domElement.requestPointerLock==='function';
let mouseLookLocked=false;

function refreshDesktopControlHint(){
  const hintEl=$('#desktopControlsHint');
  if(!hintEl||!platform.isDesktop) return;
  hintEl.innerHTML=(mouseLookLocked||!pointerLockSupported)
    ? '<b>W A S D</b> - move<br><b>Mouse</b> - look<br><b>Click</b> - interact<br><b>Esc</b> - deactivate mouse look'
    : '<b>W A S D</b> - move<br><b>Click</b> - activate mouse look<br><b>Esc</b> - release cursor';
}

function lockMouseLook(){
  if(!pointerLockSupported||!controls.enabled) return;
  renderer.domElement.requestPointerLock();
  document.body.style.cursor='none';
}
function unlockMouseLook(){
  if(document.pointerLockElement===renderer.domElement) document.exitPointerLock();
  document.body.style.cursor='auto';
}

// Keyboard input handling
addEventListener('keydown',e=>{
  if(controls.enabled&&(e.code==='KeyW'||e.code==='KeyA'||e.code==='KeyS'||e.code==='KeyD'||e.code==='ArrowUp'||e.code==='ArrowDown'||e.code==='ArrowLeft'||e.code==='ArrowRight'))
    e.preventDefault();
  keys[e.code]=true;
  if(e.code==='Escape') unlockMouseLook();
});
addEventListener('keyup',e=>keys[e.code]=false);

// Pointer lock lifecycle
if(pointerLockSupported){
  document.addEventListener('pointerlockchange',()=>{
    mouseLookLocked=document.pointerLockElement===renderer.domElement;
    refreshDesktopControlHint();
    if(!mouseLookLocked) document.body.style.cursor='auto';
  });
  document.addEventListener('pointerlockerror',()=>{ 
    mouseLookLocked=false;
    refreshDesktopControlHint();
    document.body.style.cursor='auto';
  });
}

let dragging=false,lx=0,ly=0,downT=0,downX=0,downY=0;
let joystickActive=false,joystickX=0,joystickY=0;

// Desktop mouse pointer lock: click to lock, then move + WASD both work
renderer.domElement.addEventListener('pointerdown',e=>{
  if(!controls.enabled) return;

  if(pointerLockSupported&&e.pointerType==='mouse'){
    if(!mouseLookLocked){
      lockMouseLook();
      return;
    }
    tryInteract();
    return;
  }

  if(e.pointerType==='mouse'){
    tryInteract();
    return;
  }

  // Touch or pen - use swipe for look or joystick for movement
  if(e.pointerType==='touch'){
    dragging=true; lx=e.clientX; ly=e.clientY; downT=performance.now(); downX=e.clientX; downY=e.clientY;
  }
});

addEventListener('pointermove',e=>{
  if(!controls.enabled) return;
  
  if(mouseLookLocked&&e.pointerType==='mouse'){
    // Mouse look via pointer lock - works with WASD movement simultaneously
    yaw-=e.movementX*.0026; pitch-=e.movementY*.0026;
    pitch=Math.max(-1.2,Math.min(1.2,pitch));
    return;
  }
  
  if(!dragging||e.pointerType!=='touch') return;
  
  // Touch swipe for camera look (when not using joystick)
  yaw-=(e.clientX-lx)*.0032; pitch-=(e.clientY-ly)*.0032;
  pitch=Math.max(-1.2,Math.min(1.2,pitch));
  lx=e.clientX; ly=e.clientY;
});

addEventListener('pointerup',e=>{
  if(e.pointerType!=='touch') return;
  if(!dragging) return; 
  dragging=false;
  
  const moved=Math.hypot(e.clientX-downX,e.clientY-downY);
  if(controls.enabled&&moved<8&&performance.now()-downT<300) tryInteract();
});

const ray=new THREE.Raycaster();
let hoverObj=null;
function castCenter(){
  ray.setFromCamera({x:0,y:0},camera);
  const hits=ray.intersectObjects(interactables,false);
  return (hits.length&&hits[0].distance<3.4)?hits[0].object:null;
}
function tryInteract(){ const o=castCenter(); if(o) o.userData.action(); }

// Mobile: Virtual joystick for movement (faint, fits UI scheme)
if(platform.isTouchDevice){
  const joystickHTML=`
    <div id="joystick-container" style="position:absolute;bottom:80px;left:50%;transform:translateX(-50%);pointer-events:auto;width:160px;height:160px;">
      <div style="position:relative;width:100%;height:100%;border:1px solid rgba(218,165,32,.2);border-radius:50%;background:rgba(10,9,8,.15);box-shadow:inset 0 0 20px rgba(0,0,0,.4)">
        <div id="joystick-thumb" style="position:absolute;width:60px;height:60px;background:rgba(218,165,32,.25);border:1px solid rgba(218,165,32,.4);border-radius:50%;left:50px;top:50px;transform:translate(-50%,-50%);box-shadow:0 0 10px rgba(218,165,32,.2);transition:all 0.05s linear"></div>
      </div>
    </div>
  `;
  const hudDiv=$('#hud');
  const tempDiv=document.createElement('div');
  tempDiv.innerHTML=joystickHTML;
  hudDiv.appendChild(tempDiv.firstElementChild);
  
  const joystickContainer=$('#joystick-container');
  const joystickThumb=$('#joystick-thumb');
  let joystickPointerId=null;
  
  joystickContainer.addEventListener('pointerdown',e=>{
    if(!controls.enabled) return;
    joystickPointerId=e.pointerId;
    joystickActive=true;
  });
  
  document.addEventListener('pointermove',e=>{
    if(!joystickActive||e.pointerId!==joystickPointerId) return;
    
    const rect=joystickContainer.getBoundingClientRect();
    const cx=rect.left+rect.width/2, cy=rect.top+rect.height/2;
    const dx=e.clientX-cx, dy=e.clientY-cy;
    const dist=Math.hypot(dx,dy);
    const maxDist=70;
    
    joystickX=Math.min(1,dist/maxDist)*(dx/dist||0);
    joystickY=Math.min(1,dist/maxDist)*(dy/dist||0);
    
    const tx=joystickX*70, ty=joystickY*70;
    joystickThumb.style.transform=`translate(calc(-50% + ${tx}px), calc(-50% + ${ty}px))`;
  });
  
  document.addEventListener('pointerup',e=>{
    if(e.pointerId!==joystickPointerId) return;
    joystickActive=false;
    joystickX=0;
    joystickY=0;
    joystickThumb.style.transform='translate(-50%,-50%)';
  });
}
function moveStep(dt){
  if(!controls.enabled) return;
  const sp=2.4*dt;
  const f=new THREE.Vector3(-Math.sin(yaw),0,-Math.cos(yaw));
  const r=new THREE.Vector3(Math.cos(yaw),0,-Math.sin(yaw));
  const v=new THREE.Vector3();
  
  // Keyboard input
  if(keys.KeyW||keys.ArrowUp) v.add(f);
  if(keys.KeyS||keys.ArrowDown) v.sub(f);
  if(keys.KeyD||keys.ArrowRight) v.add(r);
  if(keys.KeyA||keys.ArrowLeft) v.sub(r);
  
  // Mobile joystick input
  if(joystickActive&&(Math.abs(joystickX)>0.1||Math.abs(joystickY)>0.1)){
    v.add(f.clone().multiplyScalar(-joystickY));
    v.add(r.clone().multiplyScalar(joystickX));
  }
  
  if(v.lengthSq()>0){
    v.normalize().multiplyScalar(sp);
    camera.position.add(v);
    camera.position.x=Math.max(-ROOM.w/2+bounds.insetX,Math.min(ROOM.w/2-bounds.insetX,camera.position.x));
    camera.position.z=Math.max(-ROOM.d/2+bounds.insetZ,Math.min(ROOM.d/2-bounds.insetZ,camera.position.z));
    state.walked+=sp;
    if(state.walked>6) clearMission('walk');
  }
}

